// ─── Scroll reveal hook ───
function useReveal(threshold = 0.15) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => {
        if (e.isIntersecting) {
          setVis(true);
          obs.disconnect();
        }
      },
      { threshold, rootMargin: "0px 0px -30px 0px" },
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, vis];
}

function Reveal({ children, delay = 0, style = {}, className = "" }) {
  const [ref, vis] = useReveal();
  return (
    <div
      ref={ref}
      className={className}
      style={{
        opacity: vis ? 1 : 0,
        transform: vis ? "translateY(0)" : "translateY(28px)",
        transition: `opacity .7s cubic-bezier(.16,1,.3,1) ${delay}s, transform .7s cubic-bezier(.16,1,.3,1) ${delay}s`,
        ...style,
      }}
    >
      {children}
    </div>
  );
}

// ─── Animated bar ───
function AnimBar({
  label,
  pct,
  variant = "muted",
  labelStyle = {},
  delay = 0,
}) {
  const [ref, vis] = useReveal(0.2);
  const colors = {
    gold: { bg: T.gold, c: T.black },
    sand: { bg: T.sand, c: T.black },
    muted: { bg: T.w15, c: T.w50 },
  };
  const { bg, c } = colors[variant] || colors.muted;
  return (
    <div
      ref={ref}
      style={{ display: "flex", alignItems: "center", gap: ".75rem" }}
    >
      <div
        style={{
          flex: "0 0 120px",
          fontSize: ".82rem",
          color: T.w50,
          textAlign: "right",
          lineHeight: 1.3,
          ...labelStyle,
        }}
      >
        {label}
      </div>
      <div
        style={{
          flex: 1,
          height: 30,
          background: T.w04,
          borderRadius: 4,
          overflow: "hidden",
        }}
      >
        <div
          style={{
            height: "100%",
            borderRadius: 4,
            background: bg,
            width: vis ? `${pct}%` : "0%",
            transition: `width 1.2s cubic-bezier(.16,1,.3,1) ${delay}s`,
            display: "flex",
            alignItems: "center",
            justifyContent: "flex-end",
            paddingRight: ".65rem",
            fontSize: ".75rem",
            fontWeight: 700,
            color: c,
          }}
        >
          {pct}%
        </div>
      </div>
    </div>
  );
}

// ─── Donut chart ───
function Donut({ pct, label, color = T.gold }) {
  const [ref, vis] = useReveal(0.2);
  const r = 54,
    circ = 2 * Math.PI * r;
  return (
    <div ref={ref} style={{ textAlign: "center" }}>
      <div
        style={{
          width: 130,
          height: 130,
          margin: "0 auto .75rem",
          position: "relative",
        }}
      >
        <svg
          viewBox="0 0 128 128"
          style={{ width: "100%", height: "100%", transform: "rotate(-90deg)" }}
        >
          <circle
            cx={64}
            cy={64}
            r={r}
            fill="none"
            strokeWidth={8}
            stroke={T.w08}
          />
          <circle
            cx={64}
            cy={64}
            r={r}
            fill="none"
            strokeWidth={8}
            stroke={color}
            strokeLinecap="round"
            strokeDasharray={circ}
            strokeDashoffset={vis ? circ * (1 - pct / 100) : circ}
            style={{
              transition: "stroke-dashoffset 1.4s cubic-bezier(.16,1,.3,1)",
            }}
          />
        </svg>
        <div
          style={{
            position: "absolute",
            inset: 0,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: T.fd,
            fontSize: "1.5rem",
            fontWeight: 700,
            color,
          }}
        >
          {pct}%
        </div>
      </div>
      <div
        style={{
          fontSize: ".75rem",
          color: T.w50,
          lineHeight: 1.45,
          maxWidth: 150,
          margin: "0 auto",
        }}
      >
        {label}
      </div>
    </div>
  );
}

