function Btn({
  children,
  variant = "gold",
  small,
  href = "#",
  onClick,
  block,
  style: s = {},
}) {
  const base = {
    display: "inline-flex",
    alignItems: "center",
    justifyContent: "center",
    gap: ".5rem",
    padding: small ? ".6rem 1.3rem" : ".85rem 2rem",
    fontSize: small ? ".82rem" : ".92rem",
    fontWeight: 600,
    borderRadius: 100,
    border: "none",
    cursor: "pointer",
    textDecoration: "none",
    fontFamily: T.fb,
    transition: "all .25s cubic-bezier(.16,1,.3,1)",
    width: block ? "100%" : undefined,
    ...s,
  };
  const styles = {
    gold: { ...base, background: T.gold, color: T.black },
    ghost: {
      ...base,
      background: "transparent",
      color: T.w,
      border: `1px solid ${T.w15}`,
    },
  };
  return (
    <a href={href} onClick={onClick} style={styles[variant] || styles.gold}>
      {children}
    </a>
  );
}

function SupportForm({ maxW = 480, compact, onSubmit }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [role, setRole] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async () => {
    setError("");
    if (!name.trim() || !email.trim() || !role) {
      setError("Please fill in your name, email, and select who you are.");
      return;
    }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError("Please enter a valid email address.");
      return;
    }
    setLoading(true);
    try {
      const res = await fetch("/api/subscribe", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: name.trim(), email: email.trim(), role }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || "Something went wrong. Please try again.");
        setLoading(false);
        return;
      }
      setLoading(false);
      if (onSubmit) onSubmit();
    } catch (err) {
      setError("Network error. Please try again.");
      setLoading(false);
    }
  };

  const inputStyle = {
    flex: 1,
    padding: compact ? ".7rem 1rem" : ".8rem 1.2rem",
    background: T.w04,
    border: `1px solid ${T.w15}`,
    borderRadius: 10,
    color: T.w,
    fontFamily: T.fb,
    fontSize: ".88rem",
    outline: "none",
  };
  return (
    <div style={{ maxWidth: maxW, margin: "0 auto" }}>
      <div
        className="support-form-row"
        style={{ display: "flex", gap: ".5rem", marginBottom: ".5rem" }}
      >
        <input
          type="text"
          placeholder="First name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          style={inputStyle}
        />
        <input
          type="email"
          placeholder="Email address"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          style={{ ...inputStyle, flex: 1.5 }}
        />
      </div>
      <select
        value={role}
        onChange={(e) => setRole(e.target.value)}
        style={{
          width: "100%",
          padding: compact ? ".7rem 1rem" : ".8rem 1.2rem",
          background: T.w04,
          border: `1px solid ${T.w15}`,
          borderRadius: 10,
          color: role ? T.w : T.w50,
          fontFamily: T.fb,
          fontSize: ".88rem",
          outline: "none",
          marginBottom: ".5rem",
          appearance: "none",
          backgroundImage: `url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1L5 5L9 1' stroke='%23999' stroke-width='1.5' stroke-linecap='round'/%3E%3C/svg%3E")`,
          backgroundRepeat: "no-repeat",
          backgroundPosition: "right 1rem center",
        }}
      >
        <option value="" style={{ color: T.w50 }}>
          I am a...
        </option>
        <option value="public" style={{ color: "#000" }}>
          member of the public
        </option>
        <option value="dentist" style={{ color: "#000" }}>
          dentist or dental professional
        </option>
        <option value="industry" style={{ color: "#000" }}>
          member of the dental industry
        </option>
        <option value="government" style={{ color: "#000" }}>
          government or policy professional
        </option>
        <option value="philanthropy" style={{ color: "#000" }}>
          philanthropist or impact investor
        </option>
      </select>
      {error && (
        <div
          style={{
            color: "#ff6b6b",
            fontSize: ".8rem",
            marginBottom: ".4rem",
            fontFamily: T.fb,
          }}
        >
          {error}
        </div>
      )}
      <button
        type="button"
        onClick={handleSubmit}
        disabled={loading}
        style={{
          width: "100%",
          padding: compact ? ".75rem" : ".9rem",
          background: loading ? T.gd : T.gold,
          color: T.black,
          border: "none",
          fontWeight: 700,
          fontSize: ".95rem",
          borderRadius: 10,
          cursor: loading ? "not-allowed" : "pointer",
          fontFamily: T.fb,
          opacity: loading ? 0.7 : 1,
          transition: "opacity .2s",
        }}
      >
        {loading ? "Submitting..." : "I support dental in Medicare"}
      </button>
    </div>
  );
}

