// ─── Market size projection chart ───
function MarketChart() {
  const [ref, vis] = useReveal(0.2);
  const years = [
    "2026",
    "2027",
    "2028",
    "2029",
    "2030",
    "2031",
    "2032",
    "2033",
    "2034",
    "2035",
    "2036",
  ];
  // Baseline: ~3.5% CAGR from $14.5B
  const baseline = [
    14.5, 15.0, 15.5, 16.1, 16.6, 17.2, 17.8, 18.4, 19.1, 19.7, 20.4,
  ];
  // With ADS: ~10-12% early years (triple baseline rate), settling to ~8%, reaching ~$29B+ by 2036
  const withADS = [
    14.5, 15.2, 16.8, 18.7, 20.5, 22.1, 23.8, 25.3, 26.8, 28.0, 29.2,
  ];
  const maxVal = 32;
  const chartH = 220;

  return (
    <div
      ref={ref}
      style={{
        marginTop: "2rem",
        padding: "1.5rem",
        background: T.w04,
        border: `1px solid ${T.w08}`,
        borderRadius: 16,
      }}
    >
      <div
        style={{
          fontSize: ".72rem",
          color: T.w30,
          fontWeight: 600,
          letterSpacing: ".06em",
          textTransform: "uppercase",
          marginBottom: ".5rem",
        }}
      >
        Projected dental services market ($B)
      </div>
      <div
        style={{
          display: "flex",
          gap: "1.25rem",
          marginBottom: "1rem",
          fontSize: ".7rem",
          color: T.w30,
        }}
      >
        <span style={{ display: "flex", alignItems: "center", gap: ".3rem" }}>
          <span
            style={{
              width: 10,
              height: 10,
              borderRadius: 2,
              background: T.w15,
            }}
          />
          Without ADS
        </span>
        <span style={{ display: "flex", alignItems: "center", gap: ".3rem" }}>
          <span
            style={{
              width: 10,
              height: 10,
              borderRadius: 2,
              background: T.gold,
            }}
          />
          With ADS
        </span>
      </div>
      <div
        style={{
          position: "relative",
          height: chartH + 30,
          overflow: "hidden",
        }}
      >
        {/* Y-axis gridlines */}
        {[0, 8, 16, 24, 32].map((v) => (
          <div
            key={v}
            style={{
              position: "absolute",
              left: 0,
              right: 0,
              bottom: (v / maxVal) * chartH + 24,
              borderTop: `1px solid ${v === 0 ? T.w15 : T.w04}`,
            }}
          >
            <span
              style={{
                position: "absolute",
                left: 0,
                top: -8,
                fontSize: ".6rem",
                color: T.w15,
              }}
            >
              ${v}B
            </span>
          </div>
        ))}
        {/* Bars */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-around",
            alignItems: "flex-end",
            height: chartH,
            paddingLeft: 30,
            paddingRight: 4,
          }}
        >
          {years.map((yr, i) => {
            const bH = (baseline[i] / maxVal) * chartH;
            const aH = (withADS[i] / maxVal) * chartH;
            return (
              <div
                key={yr}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  gap: 2,
                  flex: 1,
                }}
              >
                <div
                  style={{
                    display: "flex",
                    gap: 3,
                    alignItems: "flex-end",
                    height: chartH,
                  }}
                >
                  <div
                    style={{
                      width: 8,
                      height: vis ? bH : 0,
                      background: T.w15,
                      borderRadius: "2px 2px 0 0",
                      transition: `height 1s cubic-bezier(.16,1,.3,1) ${i * 0.06}s`,
                    }}
                  />
                  <div
                    style={{
                      width: 8,
                      height: vis ? aH : 0,
                      background: i >= 2 ? T.gold : T.gd,
                      borderRadius: "2px 2px 0 0",
                      transition: `height 1s cubic-bezier(.16,1,.3,1) ${i * 0.06 + 0.05}s`,
                    }}
                  />
                </div>
              </div>
            );
          })}
        </div>
        {/* X-axis labels */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-around",
            paddingLeft: 30,
            paddingRight: 4,
            marginTop: 4,
          }}
        >
          {years.map((yr, i) => (
            <div
              key={yr}
              style={{
                flex: 1,
                textAlign: "center",
                fontSize: ".58rem",
                color: T.w15,
              }}
            >
              {i % 2 === 0 ? yr : ""}
            </div>
          ))}
        </div>
      </div>
      <div
        style={{
          marginTop: ".75rem",
          fontSize: ".65rem",
          color: T.w15,
          fontStyle: "italic",
        }}
      >
        Projected. Baseline ~3.5% CAGR (IBISWorld). ADS scenario assumes tripled
        growth in early years as funded patients enter the system. M4D
        estimates.
      </div>
    </div>
  );
}

