// ─── Quote component with optional portrait ───
function QuoteBlock({ text, author, role, portrait, reverse }) {
  return (
    <div
      style={{
        padding: "5rem 0",
        borderTop: `1px solid ${T.w08}`,
        borderBottom: `1px solid ${T.w08}`,
      }}
    >
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 2rem" }}>
        <Reveal>
          <div
            className="quote-row"
            style={{
              display: "flex",
              gap: "3rem",
              alignItems: "center",
              flexDirection: reverse ? "row-reverse" : "row",
              maxWidth: 900,
              margin: "0 auto",
            }}
          >
            {portrait && (
              <div className="quote-portrait" style={{ flex: "0 0 120px" }}>
                <div
                  style={{
                    width: 120,
                    height: 120,
                    borderRadius: "50%",
                    overflow: "hidden",
                    border: `3px solid ${T.gold}`,
                    flexShrink: 0,
                  }}
                >
                  <img
                    src={portrait}
                    alt={author}
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                      filter: "grayscale(100%) contrast(1.1)",
                    }}
                  />
                </div>
              </div>
            )}
            <div
              style={{
                textAlign: portrait ? "left" : "center",
                position: "relative",
                flex: 1,
              }}
            >
              {!portrait && (
                <span
                  style={{
                    fontFamily: T.fd,
                    fontSize: "7rem",
                    color: T.gold,
                    opacity: 0.2,
                    lineHeight: 0,
                    position: "absolute",
                    top: 0,
                    left: "-1.5rem",
                  }}
                >
                  "
                </span>
              )}
              <p
                style={{
                  fontFamily: T.fd,
                  fontSize: "clamp(1.1rem,2vw,1.4rem)",
                  fontStyle: "italic",
                  lineHeight: 1.65,
                  color: T.w90,
                  marginBottom: "1.25rem",
                }}
              >
                "{text}"
              </p>
              <p style={{ fontSize: ".85rem", color: T.gold, fontWeight: 500 }}>
                {author}{" "}
                <span style={{ color: T.w30, fontWeight: 400 }}>{role}</span>
              </p>
            </div>
          </div>
        </Reveal>
      </div>
    </div>
  );
}

